// app/components/server-timestamp.tsx
/**
 * ServerTimestamp — a React Server Component that renders the current
 * server time on every request.
 *
 * To prevent static prerendering (which would bake in the build
 * timestamp), the consuming route uses `export const dynamic = 'force-dynamic'`.
 * That is the simplest way to mark a route as fully dynamic.
 *
 * Alternative approaches (per-component, without route-level config):
 *
 *   1. import { unstable_noStore as noStore } from 'next/cache'
 *      noStore()  // call at the top of the component
 *
 *   2. import { connection } from 'next/navigation'
 *      await connection()  // tells Next.js the component needs the request context
 */

export default function ServerTimestamp() {
  const now = new Date()
  const iso = now.toISOString()
  const local = now.toLocaleString("en-US", { timeZoneName: "short" })

  return (
    <p>
      <strong>Server Timestamp:</strong> {local} ({iso})
    </p>
  )
}

